import { useSearchParams } from 'react-router-dom';

export default function SearchBar({ districts = [] }) {
  const [searchParams, setSearchParams] = useSearchParams();
  const query = searchParams.get('q') || '';
  const district = searchParams.get('district') || '';
  const priceRange = searchParams.get('priceRange') || '';

  const updateParams = (updates) => {
    const newParams = new URLSearchParams(searchParams);
    Object.entries(updates).forEach(([key, value]) => {
      if (value) {
        newParams.set(key, value);
      } else {
        newParams.delete(key);
      }
    });
    setSearchParams(newParams, { replace: true });
  };

  return (
    <div className="search-bar">
      <input
        type="text"
        placeholder="Search properties..."
        value={query}
        onChange={(e) => updateParams({ q: e.target.value })}
        aria-label="Search"
      />
      <select 
        value={district} 
        onChange={(e) => updateParams({ district: e.target.value })}
        aria-label="District"
      >
        <option value="">All Districts</option>
        {districts.map(d => (
          <option key={d} value={d}>{d}</option>
        ))}
      </select>
      <select 
        value={priceRange} 
        onChange={(e) => updateParams({ priceRange: e.target.value })}
        aria-label="Price Range"
      >
        <option value="">All Prices</option>
        <option value="0-1000">Under $1000</option>
        <option value="1000-2000">$1000 - $2000</option>
        <option value="2000+">Over $2000</option>
      </select>
    </div>
  );
}

import { useState, useEffect } from 'react';

export function useProperties() {
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch('/api/properties', {
      headers: {
        'X-Trore-Auth': 'v1-alpha'
      }
    })
      .then(res => {
        if (!res.ok) throw new Error('Failed to fetch');
        return res.json();
      })
      .then(data => {
        setProperties(data);
        setLoading(false);
      })
      .catch(err => {
        setError(err.message);
        setLoading(false);
      });
  }, []);

  return { properties, loading, error };
}

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

// Custom plugin to mock the API
const mockApiPlugin = () => ({
  name: 'mock-api',
  configureServer(server) {
    server.middlewares.use('/api/properties', (req, res) => {
      const authHeader = req.headers['x-trore-auth'];
